import{_ as e,o as d,c as a,a2 as o}from"./chunks/framework.BKchhTkY.js";const _=JSON.parse('{"title":"readelf 工具输出文件说明","description":"","frontmatter":{},"headers":[],"relativePath":"guide/other/readelf输出文件说明.md","filePath":"guide/other/readelf输出文件说明.md","lastUpdated":1783672098000}'),s={name:"guide/other/readelf输出文件说明.md"};function n(c,t,l,r,i,p){return d(),a("div",null,[...t[0]||(t[0]=[o(`<h1 id="readelf-工具输出文件说明" tabindex="-1">readelf 工具输出文件说明 <a class="header-anchor" href="#readelf-工具输出文件说明" aria-label="Permalink to &quot;readelf 工具输出文件说明&quot;">​</a></h1><p>开启 <code>GENERATE_READELF</code> 宏后，编译会在 <code>build/elf/</code> 目录下生成以下文件。</p><h2 id="文件列表" tabindex="-1">文件列表 <a class="header-anchor" href="#文件列表" aria-label="Permalink to &quot;文件列表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>readelf 选项</th><th>文件名</th><th>说明</th></tr></thead><tbody><tr><td><code>-aW</code></td><td><code>BetaRobot.elf_all.txt</code></td><td>完整的 ELF 文件信息，包含 ELF 头、程序头、节头、符号表、重定位表等所有非调试信息</td></tr><tr><td><code>--debug-dump=abbrev</code></td><td><code>BetaRobot.elf_abbrev.txt</code></td><td>DWARF 缩写表，定义了调试信息条目（DIE）的缩写形式，用于压缩调试信息</td></tr><tr><td><code>--debug-dump=addr</code></td><td><code>BetaRobot.elf_addr.txt</code></td><td>DWARF 地址表，存储地址到符号的映射信息，用于加速调试器查找</td></tr><tr><td><code>--debug-dump=aranges</code></td><td><code>BetaRobot.elf_aranges.txt</code></td><td>DWARF 地址范围表，记录每个编译单元的代码地址范围，用于快速定位函数所属的编译单元</td></tr><tr><td><code>--debug-dump=cu_index</code></td><td><code>BetaRobot.elf_cu_index.txt</code></td><td>编译单元索引，用于加速在大型程序的 DWARF 信息中查找特定编译单元</td></tr><tr><td><code>--debug-dump=decodedline</code></td><td><code>BetaRobot.elf_decodedline.txt</code></td><td>解码后的行号信息，包含源文件名、行号与机器地址的完整映射，用于源码级调试</td></tr><tr><td><code>--debug-dump=frames</code></td><td><code>BetaRobot.elf_frames.txt</code></td><td>调用帧信息（CFI），记录函数栈帧布局、寄存器保存位置，用于回溯调用栈和异常处理</td></tr><tr><td><code>--debug-dump=frames-interp</code></td><td><code>BetaRobot.elf_frames-interp.txt</code></td><td>解释后的帧信息，将原始 CFI 数据转换为更易读的格式，显示每个指令位置的栈帧状态</td></tr><tr><td><code>--debug-dump=gdb_index</code></td><td><code>BetaRobot.elf_gdb_index.txt</code></td><td>GDB 索引，预计算的调试索引，加速 GDB 启动时的符号加载</td></tr><tr><td><code>--debug-dump=info</code></td><td><code>BetaRobot.elf_info.txt</code></td><td><strong>核心 DWARF 调试信息</strong>，包含：变量和函数的定义与类型、结构体/联合体/枚举的布局与字段偏移、作用域信息、源文件位置映射</td></tr><tr><td><code>--debug-dump=loc</code></td><td><code>BetaRobot.elf_loc.txt</code></td><td>位置列表，描述变量在不同代码位置的存储位置（寄存器或栈槽），因为变量可能在不同位置存活</td></tr><tr><td><code>--debug-dump=macro</code></td><td><code>BetaRobot.elf_macro.txt</code></td><td>宏定义信息，记录源码中 <code>#define</code> 定义的宏，允许调试器展开宏</td></tr><tr><td><code>--debug-dump=pubnames</code></td><td><code>BetaRobot.elf_pubnames.txt</code></td><td>公开名称表，列出所有全局可见的函数和变量名称，用于快速符号查找</td></tr><tr><td><code>--debug-dump=pubtypes</code></td><td><code>BetaRobot.elf_pubtypes.txt</code></td><td>公开类型表，列出所有全局可见的类型定义（结构体、枚举等），用于快速类型查找</td></tr><tr><td><code>--debug-dump=Ranges</code></td><td><code>BetaRobot.elf_Ranges.txt</code></td><td>地址范围列表，记录函数、变量等程序实体占用的内存地址范围，支持非连续地址范围</td></tr><tr><td><code>--debug-dump=rawline</code></td><td><code>BetaRobot.elf_rawline.txt</code></td><td>原始行号信息，直接从 <code>.debug_line</code> 节解码的数据，包含行号程序的原始状态机指令</td></tr><tr><td><code>--debug-dump=str</code></td><td><code>BetaRobot.elf_str.txt</code></td><td>DWARF 字符串表，存储调试信息中使用的所有字符串（文件名、变量名、类型名等）</td></tr><tr><td><code>--debug-dump=str-offsets</code></td><td><code>BetaRobot.elf_str-offsets.txt</code></td><td>字符串偏移表，记录字符串在字符串表中的偏移量，用于 DWARF 5 格式的字符串引用</td></tr><tr><td><code>--debug-dump=trace_abbrev</code></td><td><code>BetaRobot.elf_trace_abbrev.txt</code></td><td>追踪缩写表，用于 CTF（Compile Time Format）追踪功能的缩写定义</td></tr><tr><td><code>--debug-dump=trace_aranges</code></td><td><code>BetaRobot.elf_trace_aranges.txt</code></td><td>追踪地址范围，用于追踪功能的地址范围映射</td></tr><tr><td><code>--debug-dump=trace_info</code></td><td><code>BetaRobot.elf_trace_info.txt</code></td><td>追踪信息，记录程序的追踪点信息，用于性能分析和代码覆盖率</td></tr></tbody></table><h2 id="常用文件说明" tabindex="-1">常用文件说明 <a class="header-anchor" href="#常用文件说明" aria-label="Permalink to &quot;常用文件说明&quot;">​</a></h2><h3 id="betarobot-elf-info-txt-结构体布局查看" tabindex="-1"><code>BetaRobot.elf_info.txt</code> - 结构体布局查看 <a class="header-anchor" href="#betarobot-elf-info-txt-结构体布局查看" aria-label="Permalink to &quot;\`BetaRobot.elf_info.txt\` - 结构体布局查看&quot;">​</a></h3><p>这是最常用的文件，包含完整的 DWARF 调试信息。查看结构体字段偏移的方法：</p><ol><li>搜索 <code>DW_TAG_structure_type</code> 找到结构体定义</li><li>每个 <code>DW_TAG_member</code> 表示一个字段</li><li><code>DW_AT_data_member_location</code> 表示字段偏移量</li></ol><p>示例：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span> &lt;1&gt;&lt;0x1234&gt;: Abbrev Number: 5 (DW_TAG_structure_type)</span></span>
<span class="line"><span>    &lt;0x1235&gt;   DW_AT_name        : my_struct</span></span>
<span class="line"><span>    ...</span></span>
<span class="line"><span> &lt;2&gt;&lt;0x1250&gt;: Abbrev Number: 7 (DW_TAG_member)</span></span>
<span class="line"><span>    &lt;0x1251&gt;   DW_AT_name        : field_a</span></span>
<span class="line"><span>    &lt;0x1255&gt;   DW_AT_type        : &lt;0x2000&gt;</span></span>
<span class="line"><span>    &lt;0x1259&gt;   DW_AT_data_member_location: 0   // 偏移 0 字节</span></span>
<span class="line"><span> &lt;2&gt;&lt;0x1260&gt;: Abbrev Number: 7 (DW_TAG_member)</span></span>
<span class="line"><span>    &lt;0x1261&gt;   DW_AT_name        : field_b</span></span>
<span class="line"><span>    &lt;0x1265&gt;   DW_AT_type        : &lt;0x2010&gt;</span></span>
<span class="line"><span>    &lt;0x1269&gt;   DW_AT_data_member_location: 4   // 偏移 4 字节</span></span></code></pre></div><h3 id="betarobot-elf-frames-txt-栈帧分析" tabindex="-1"><code>BetaRobot.elf_frames.txt</code> - 栈帧分析 <a class="header-anchor" href="#betarobot-elf-frames-txt-栈帧分析" aria-label="Permalink to &quot;\`BetaRobot.elf_frames.txt\` - 栈帧分析&quot;">​</a></h3><p>用于分析函数调用栈，包含：</p><ul><li>函数入口的栈指针调整</li><li>被调用者保存寄存器的存储位置</li><li>返回地址的保存位置</li></ul><h3 id="betarobot-elf-decodedline-txt-地址映射" tabindex="-1"><code>BetaRobot.elf_decodedline.txt</code> - 地址映射 <a class="header-anchor" href="#betarobot-elf-decodedline-txt-地址映射" aria-label="Permalink to &quot;\`BetaRobot.elf_decodedline.txt\` - 地址映射&quot;">​</a></h3><p>用于将机器地址映射回源码位置：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>File name                            Line number    Starting address</span></span>
<span class="line"><span>src/main.c                                   10              0x8001234</span></span>
<span class="line"><span>src/main.c                                   11              0x8001238</span></span></code></pre></div><h2 id="使用配置" tabindex="-1">使用配置 <a class="header-anchor" href="#使用配置" aria-label="Permalink to &quot;使用配置&quot;">​</a></h2><p>在 <code>app/&lt;APP_NAME&gt;/app_cfg.h</code> 中开启：</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 编译后是否生成readelf输出文件</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 注释此行则不生成</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#define</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> GENERATE_READELF</span></span></code></pre></div>`,19)])])}const u=e(s,[["render",n]]);export{_ as __pageData,u as default};
